UPDATE coupon
SET coupon_code=#{couponCode}, seller_no=#{sellerNo}, coupon_type=#{couponType}, coupon_name=#{couponName}, benefit_type=#{benefitType},
    benefit_value=#{benefitValue}, min_order_price=#{minOrderPrice}, max_discount_price=#{maxDiscountPrice}, issue_limit=#{issueLimit},
    start_date=#{startDate}, end_date=#{endDate}, caution=#{caution}, status=#{status}
WHERE coupon_no=#{couponNo}
